#!/usr/bin/env bash
# Run on production server (104.238.162.40):
#   cd /var/www/NPPC-Website && bash scripts/add_round6_historical_cases.sh
#
# Sources / case clusters:
#   - MOVE 9 — Aug 8, 1978 Powelton Village raid + 3rd-deg murder convictions
#     for the death of Officer James J. Ramp (each sentenced 30-100 years)
#   - FALN — Fuerzas Armadas de Liberacion Nacional Puertorriquena: 1980
#     Evanston arrests + 1983 Chicago arrests; 11 commuted by Clinton 1999,
#     Carlos Alberto Torres released 2010, Oscar Lopez Rivera released 2017
#     by Obama commutation
#   - Operation Backfire / "The Family" — FBI's 2005-2007 prosecution of
#     the Eugene-based ELF cell for $20M of eco-sabotage arsons 1996-2001;
#     terrorism-enhanced federal sentences 4-13 years
#   - SHAC 7 — first Animal Enterprise Terrorism Act federal prosecution,
#     Trenton NJ March 2006; six humans + the SHAC USA org as the seventh
#     defendant; sentences 1-6 years
#
# Each php artisan call is wrapped in `|| true` so a duplicate-name failure
# (the AddPrisoner command refuses on duplicate) does not halt the script.

# === MOVE 9 — Philadelphia, August 8, 1978 ===

php artisan prisoner:add '{"name":"Debbie Sims Africa","first_name":"Debbie","middle_name":"Sims","last_name":"Africa","description":"Debbie Sims Africa is a member of the MOVE organization, a Black revolutionary back-to-nature group founded in Philadelphia by John Africa. On August 8, 1978, Philadelphia police laid siege to the MOVE compound at 33rd and Powelton in West Philadelphia, attempting to evict its residents. During the gunfire that followed, Officer James J. Ramp was killed. MOVE members and their defense have always argued that the fatal shot came from police, not from any MOVE member. Nine MOVE members — Debbie, Janine, Janet, Phil, Mike, Delbert, Eddie, Charles (Chuck), and Merle Africa — were each convicted of third-degree murder of Officer Ramp and sentenced to 30 to 100 years in Pennsylvania state prison.\n\nDebbie Sims Africa was the first of the MOVE 9 to be paroled, on June 16, 2018, after 39 years and 10 months of imprisonment. Her son Mike Africa Jr., who was born in prison shortly after her arrest in 1978 and raised on the outside, led the post-release support campaign for the surviving MOVE 9.","state":"Pennsylvania","race":"Black","gender":"Female","ideologies":["Black Liberation","Environmental","MOVE"],"affiliation":["MOVE"],"era":"1970s","in_custody":false,"released":true,"cases":[{"institution_name":"Pennsylvania Department of Corrections","institution_state":"Pennsylvania","charges":"Third-degree murder of Philadelphia Police Officer James J. Ramp during the August 8, 1978 police raid on the MOVE compound at 33rd and Powelton","arrest_date":"1978-08-08","incarceration_date":"1978-08-08","release_date":"2018-06-16","sentence":"30 to 100 years; paroled after 39 years 10 months","convicted":"Yes — third-degree murder, Philadelphia Court of Common Pleas, 1981"}]}' || true

php artisan prisoner:add '{"name":"Janine Phillips Africa","first_name":"Janine","middle_name":"Phillips","last_name":"Africa","description":"Janine Phillips Africa is a member of the MOVE organization arrested with eight others in the August 8, 1978 Philadelphia police raid on the MOVE compound at 33rd and Powelton. The day Officer James J. Ramp was killed in the gunfire of the raid; MOVE has always contended the fatal shot came from police gunfire, not from any MOVE member. The MOVE 9 were each convicted of third-degree murder and sentenced to 30 to 100 years.\n\nJanine and Janet Africa were paroled together on May 25, 2019 after 41 years in Pennsylvania state prison.","state":"Pennsylvania","race":"Black","gender":"Female","ideologies":["Black Liberation","Environmental","MOVE"],"affiliation":["MOVE"],"era":"1970s","in_custody":false,"released":true,"cases":[{"institution_name":"Pennsylvania Department of Corrections","institution_state":"Pennsylvania","charges":"Third-degree murder of Officer James J. Ramp — August 8, 1978 police raid on the MOVE compound at 33rd and Powelton","arrest_date":"1978-08-08","incarceration_date":"1978-08-08","release_date":"2019-05-25","sentence":"30 to 100 years; paroled after 41 years","convicted":"Yes — third-degree murder, Philadelphia Court of Common Pleas, 1981"}]}' || true

php artisan prisoner:add '{"name":"Janet Holloway Africa","first_name":"Janet","middle_name":"Holloway","last_name":"Africa","description":"Janet Holloway Africa is a member of the MOVE organization arrested with eight other MOVE members in the August 8, 1978 Philadelphia police raid on the MOVE compound at 33rd and Powelton. She was convicted along with the rest of the MOVE 9 of the third-degree murder of Officer James J. Ramp, despite the defense argument that police gunfire had killed Ramp. She and Janine Africa were paroled together on May 25, 2019 after 41 years in Pennsylvania state prison.","state":"Pennsylvania","race":"Black","gender":"Female","ideologies":["Black Liberation","Environmental","MOVE"],"affiliation":["MOVE"],"era":"1970s","in_custody":false,"released":true,"cases":[{"institution_name":"Pennsylvania Department of Corrections","institution_state":"Pennsylvania","charges":"Third-degree murder of Officer James J. Ramp — August 8, 1978 raid on the MOVE compound","arrest_date":"1978-08-08","incarceration_date":"1978-08-08","release_date":"2019-05-25","sentence":"30 to 100 years; paroled after 41 years","convicted":"Yes — third-degree murder, Philadelphia Court of Common Pleas, 1981"}]}' || true

php artisan prisoner:add '{"name":"Mike Africa Sr","first_name":"Mike","last_name":"Africa","description":"Mike Africa Sr. is a member of the MOVE organization arrested with eight other MOVE members in the August 8, 1978 Philadelphia police raid on the MOVE compound at 33rd and Powelton. He was convicted along with the rest of the MOVE 9 of third-degree murder of Officer James J. Ramp. He was paroled on October 23, 2018 after 40 years in Pennsylvania state prison. His wife Debbie Sims Africa was also among the MOVE 9; their son Mike Africa Jr., born in prison shortly after his mothers arrest, became one of the central organizers of the campaign that won the parole of all surviving MOVE 9 members.","state":"Pennsylvania","race":"Black","gender":"Male","ideologies":["Black Liberation","Environmental","MOVE"],"affiliation":["MOVE"],"era":"1970s","in_custody":false,"released":true,"cases":[{"institution_name":"Pennsylvania Department of Corrections","institution_state":"Pennsylvania","charges":"Third-degree murder of Officer James J. Ramp — August 8, 1978 raid on the MOVE compound","arrest_date":"1978-08-08","incarceration_date":"1978-08-08","release_date":"2018-10-23","sentence":"30 to 100 years; paroled after 40 years","convicted":"Yes — third-degree murder, Philadelphia Court of Common Pleas, 1981"}]}' || true

php artisan prisoner:add '{"name":"Phil Africa","first_name":"Phil","last_name":"Africa","description":"Phil Africa was a member of the MOVE organization arrested with eight other MOVE members in the August 8, 1978 Philadelphia police raid on the MOVE compound at 33rd and Powelton. He was convicted along with the rest of the MOVE 9 of third-degree murder of Officer James J. Ramp. He died in Pennsylvania state prison on January 10, 2015 at age 59 — the second of the MOVE 9 to die behind bars, after Merle Africas death in 1998.","state":"Pennsylvania","race":"Black","gender":"Male","death_date":"2015-01-10","ideologies":["Black Liberation","Environmental","MOVE"],"affiliation":["MOVE"],"era":"1970s","in_custody":false,"released":false,"cases":[{"institution_name":"Pennsylvania Department of Corrections","institution_state":"Pennsylvania","charges":"Third-degree murder of Officer James J. Ramp — August 8, 1978 raid on the MOVE compound","arrest_date":"1978-08-08","incarceration_date":"1978-08-08","death_in_custody_date":"2015-01-10","sentence":"30 to 100 years; died in prison January 10, 2015","convicted":"Yes — third-degree murder, Philadelphia Court of Common Pleas, 1981"}]}' || true

php artisan prisoner:add '{"name":"Merle Africa","first_name":"Merle","last_name":"Africa","description":"Merle Africa was a member of the MOVE organization arrested with eight other MOVE members in the August 8, 1978 Philadelphia police raid on the MOVE compound at 33rd and Powelton. She was convicted along with the rest of the MOVE 9 of third-degree murder of Officer James J. Ramp. She died in Pennsylvania state prison in March 1998 at age 47 — the first of the MOVE 9 to die behind bars.","state":"Pennsylvania","race":"Black","gender":"Female","death_date":"1998-03-13","ideologies":["Black Liberation","Environmental","MOVE"],"affiliation":["MOVE"],"era":"1970s","in_custody":false,"released":false,"cases":[{"institution_name":"Pennsylvania Department of Corrections","institution_state":"Pennsylvania","charges":"Third-degree murder of Officer James J. Ramp — August 8, 1978 raid on the MOVE compound","arrest_date":"1978-08-08","incarceration_date":"1978-08-08","death_in_custody_date":"1998-03-13","sentence":"30 to 100 years; died in prison March 1998","convicted":"Yes — third-degree murder, Philadelphia Court of Common Pleas, 1981"}]}' || true

php artisan prisoner:add '{"name":"Delbert Orr Africa","first_name":"Delbert","middle_name":"Orr","last_name":"Africa","description":"Delbert Orr Africa was a member of the MOVE organization arrested with eight other MOVE members in the August 8, 1978 Philadelphia police raid on the MOVE compound at 33rd and Powelton. As police led him out of the compound, three Philadelphia officers were filmed beating him with a rifle butt and a helmet — the assault was captured on television and the officers were later acquitted at a 1981 bench trial in a verdict widely considered a miscarriage of justice. He was convicted with the rest of the MOVE 9 of third-degree murder of Officer James J. Ramp. He was granted parole on December 20, 2019 and released on January 18, 2020 after 41 years in Pennsylvania state prison. He died of cancer in June 2020, six months after his release.","state":"Pennsylvania","race":"Black","gender":"Male","death_date":"2020-06-13","ideologies":["Black Liberation","Environmental","MOVE"],"affiliation":["MOVE"],"era":"1970s","in_custody":false,"released":true,"cases":[{"institution_name":"Pennsylvania Department of Corrections","institution_state":"Pennsylvania","charges":"Third-degree murder of Officer James J. Ramp — August 8, 1978 raid on the MOVE compound","arrest_date":"1978-08-08","incarceration_date":"1978-08-08","release_date":"2020-01-18","sentence":"30 to 100 years; paroled January 2020 after 41 years; died of cancer June 2020","convicted":"Yes — third-degree murder, Philadelphia Court of Common Pleas, 1981"}]}' || true

php artisan prisoner:add '{"name":"Eddie Goodman Africa","first_name":"Eddie","middle_name":"Goodman","last_name":"Africa","description":"Eddie Goodman Africa is a member of the MOVE organization arrested with eight other MOVE members in the August 8, 1978 Philadelphia police raid on the MOVE compound at 33rd and Powelton. He was convicted along with the rest of the MOVE 9 of third-degree murder of Officer James J. Ramp. He was paroled on June 21, 2019 after nearly 41 years in Pennsylvania state prison.","state":"Pennsylvania","race":"Black","gender":"Male","ideologies":["Black Liberation","Environmental","MOVE"],"affiliation":["MOVE"],"era":"1970s","in_custody":false,"released":true,"cases":[{"institution_name":"Pennsylvania Department of Corrections","institution_state":"Pennsylvania","charges":"Third-degree murder of Officer James J. Ramp — August 8, 1978 raid on the MOVE compound","arrest_date":"1978-08-08","incarceration_date":"1978-08-08","release_date":"2019-06-21","sentence":"30 to 100 years; paroled June 2019 after nearly 41 years","convicted":"Yes — third-degree murder, Philadelphia Court of Common Pleas, 1981"}]}' || true

php artisan prisoner:add '{"name":"Charles Sims Africa","first_name":"Charles","middle_name":"Sims","last_name":"Africa","aka":"Chuck Africa","description":"Charles \"Chuck\" Sims Africa was the youngest of the MOVE 9, only 18 years old at the time of the August 8, 1978 Philadelphia police raid on the MOVE compound at 33rd and Powelton. He was convicted with the rest of the MOVE 9 of third-degree murder of Officer James J. Ramp. He was the last of the MOVE 9 either to be paroled or to die behind bars — released on February 7, 2020 after 41 years in Pennsylvania state prison. He died of cancer in 2021, less than two years after his release.","state":"Pennsylvania","race":"Black","gender":"Male","death_date":"2021-04-30","ideologies":["Black Liberation","Environmental","MOVE"],"affiliation":["MOVE"],"era":"1970s","in_custody":false,"released":true,"cases":[{"institution_name":"Pennsylvania Department of Corrections","institution_state":"Pennsylvania","charges":"Third-degree murder of Officer James J. Ramp — August 8, 1978 raid on the MOVE compound","arrest_date":"1978-08-08","incarceration_date":"1978-08-08","release_date":"2020-02-07","sentence":"30 to 100 years; paroled February 2020 after 41 years; died of cancer 2021","convicted":"Yes — third-degree murder, Philadelphia Court of Common Pleas, 1981"}]}' || true

# === FALN — Fuerzas Armadas de Liberacion Nacional Puertorriquena ===

php artisan prisoner:add '{"name":"Oscar Lopez Rivera","first_name":"Oscar","last_name":"Lopez Rivera","description":"Oscar López Rivera is a Puerto Rican independence leader, decorated U.S. Army Vietnam War veteran (Bronze Star), and one of the longest-held political prisoners in U.S. history. He was a leader of the Fuerzas Armadas de Liberación Nacional Puertorriqueña (FALN), the clandestine organization that conducted bombings of U.S. military, government, and corporate sites between 1974 and 1983 in support of Puerto Rican independence. He was arrested on May 29, 1981 in Glenview, Illinois, and convicted in 1981 of seditious conspiracy. He was sentenced to 55 years in federal prison; an additional 15 years was added in 1988 in connection with an alleged plot to escape from federal prison alongside Black Liberation Army member Kojo Bomani Sababu (Grailing Brown).\n\nIn 1999 President Clinton offered him clemency on the condition that he renounce violence; he refused as long as 11 of his FALN co-defendants remained imprisoned. Those 11 accepted Clintons clemency. He continued to serve. After 35 years in federal prison, on January 17, 2017 — three days before leaving office — President Obama commuted his sentence. He was released on May 17, 2017 to widespread celebration in Puerto Rico and a heros welcome at the Puerto Rican Day parade in New York City.","state":"Illinois","race":"Hispanic","gender":"Male","birthdate":"1943-01-06","ideologies":["Puerto Rican Independence","Anti-imperialist"],"affiliation":["FALN","U.S. Army (Vietnam)"],"era":"1980s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","charges":"Seditious conspiracy in support of Puerto Rican independence; subsequently 1988 conspiracy to escape from federal prison","arrest_date":"1981-05-29","incarceration_date":"1981-05-29","release_date":"2017-05-17","sentence":"55 years federal prison + 15 years for 1988 conspiracy = 70 years total; commuted by President Obama January 17, 2017 after 35 years","convicted":"Yes — federal seditious conspiracy, 1981"}]}' || true

php artisan prisoner:add '{"name":"Carlos Alberto Torres","first_name":"Carlos","middle_name":"Alberto","last_name":"Torres","description":"Carlos Alberto Torres was one of the leaders of the Fuerzas Armadas de Liberación Nacional Puertorriqueña (FALN). He was arrested in 1980 and convicted of seditious conspiracy in support of Puerto Rican independence. He was sentenced in 1980 to 78 years in federal prison. He refused President Clintons 1999 clemency offer in solidarity with the few FALN prisoners not included in that offer. After 30 years in federal prison he was released on parole on July 26, 2010 and returned to Puerto Rico to a heros welcome.","state":"Illinois","race":"Hispanic","gender":"Male","ideologies":["Puerto Rican Independence","Anti-imperialist"],"affiliation":["FALN"],"era":"1980s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","charges":"Seditious conspiracy — leadership of the FALN in support of Puerto Rican independence","arrest_date":"1980-04-04","incarceration_date":"1980-04-04","release_date":"2010-07-26","sentence":"78 years federal prison; paroled after 30 years","convicted":"Yes — federal seditious conspiracy, 1980"}]}' || true

php artisan prisoner:add '{"name":"Elizam Escobar","first_name":"Elizam","last_name":"Escobar","description":"Elizam Escobar is a Puerto Rican independentista, painter, and political theorist who was one of 11 FALN members arrested on April 4, 1980 in Evanston, Illinois. He refused to participate in his trial, asserting that he did not recognize the authority of the United States over Puerto Rico, and was convicted of seditious conspiracy. He was sentenced to 60 years in federal prison and served 19 years before being released by President Clintons clemency on September 10, 1999. From inside prison he produced an internationally recognized body of paintings that has been exhibited at the Whitney Biennial and other major venues.","state":"Illinois","race":"Hispanic","gender":"Male","ideologies":["Puerto Rican Independence","Anti-imperialist"],"affiliation":["FALN"],"era":"1980s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","charges":"Seditious conspiracy — FALN, in support of Puerto Rican independence","arrest_date":"1980-04-04","incarceration_date":"1980-04-04","release_date":"1999-09-10","sentence":"60 years federal prison; commuted by President Clinton September 1999 after 19 years","convicted":"Yes — federal seditious conspiracy, 1981"}]}' || true

php artisan prisoner:add '{"name":"Ricardo Jimenez","first_name":"Ricardo","last_name":"Jimenez","description":"Ricardo Jimenez was one of 11 FALN members arrested on April 4, 1980 in Evanston, Illinois. He was convicted of seditious conspiracy and sentenced to a long federal prison term. He served 19 years before being released by President Clintons clemency on September 10, 1999.","state":"Illinois","race":"Hispanic","gender":"Male","ideologies":["Puerto Rican Independence","Anti-imperialist"],"affiliation":["FALN"],"era":"1980s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","charges":"Seditious conspiracy — FALN, in support of Puerto Rican independence","arrest_date":"1980-04-04","incarceration_date":"1980-04-04","release_date":"1999-09-10","sentence":"Long federal prison term; commuted by President Clinton September 1999","convicted":"Yes — federal seditious conspiracy, 1981"}]}' || true

