php artisan prisoner:add '{"name":"Dylcia Pagan","first_name":"Dylcia","middle_name":"Noemi","last_name":"Pagan","description":"Dylcia Pagán was one of 11 FALN members arrested on April 4, 1980 in Evanston, Illinois. She was convicted of seditious conspiracy and sentenced to 55 years in federal prison. She served 19 years before being released by President Clintons clemency on September 10, 1999. She was separated from her son for the duration of her imprisonment, and the family-separation aspect of the FALN cases became one of the central organizing themes of the international campaign for clemency.","state":"Illinois","race":"Hispanic","gender":"Female","ideologies":["Puerto Rican Independence","Anti-imperialist"],"affiliation":["FALN"],"era":"1980s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","charges":"Seditious conspiracy — FALN, in support of Puerto Rican independence","arrest_date":"1980-04-04","incarceration_date":"1980-04-04","release_date":"1999-09-10","sentence":"55 years federal prison; commuted by President Clinton September 1999 after 19 years","convicted":"Yes — federal seditious conspiracy, 1981"}]}' || true

php artisan prisoner:add '{"name":"Alicia Rodriguez","first_name":"Alicia","last_name":"Rodriguez","description":"Alicia Rodriguez was one of 11 FALN members arrested on April 4, 1980 in Evanston, Illinois. She was convicted of seditious conspiracy in support of Puerto Rican independence and sentenced to a long federal prison term. She served 19 years before being released by President Clintons clemency on September 10, 1999. Her sister Ida Luz Rodriguez was arrested with her.","state":"Illinois","race":"Hispanic","gender":"Female","ideologies":["Puerto Rican Independence","Anti-imperialist"],"affiliation":["FALN"],"era":"1980s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","charges":"Seditious conspiracy — FALN, in support of Puerto Rican independence","arrest_date":"1980-04-04","incarceration_date":"1980-04-04","release_date":"1999-09-10","sentence":"Long federal prison term; commuted by President Clinton September 1999 after 19 years","convicted":"Yes — federal seditious conspiracy, 1981"}]}' || true

