php artisan prisoner:add '{"name":"Luis Rosa","first_name":"Luis","last_name":"Rosa","description":"Luis Rosa was 19 years old, just out of high school, when he was arrested with 10 other FALN members on April 4, 1980 in Evanston, Illinois. He was convicted of seditious conspiracy in support of Puerto Rican independence and sentenced to 105 years in federal prison — the longest sentence of any of the 11 defendants. He served 19 years before being released by President Clintons clemency on September 10, 1999.","state":"Illinois","race":"Hispanic","gender":"Male","ideologies":["Puerto Rican Independence","Anti-imperialist"],"affiliation":["FALN"],"era":"1980s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","charges":"Seditious conspiracy — FALN, in support of Puerto Rican independence","arrest_date":"1980-04-04","incarceration_date":"1980-04-04","release_date":"1999-09-10","sentence":"105 years federal prison; commuted by President Clinton September 1999 after 19 years","convicted":"Yes — federal seditious conspiracy, 1981"}]}' || true

