php artisan prisoner:add '{"name":"Edwin Cortes","first_name":"Edwin","last_name":"Cortes","description":"Edwin Cortés was arrested on June 29, 1983 in Chicago, in the second wave of FALN arrests, after FBI surveillance documented him allegedly providing bomb-making instruction. He was convicted of seditious conspiracy in support of Puerto Rican independence and sentenced to a long federal prison term. He served 16 years before being released by President Clintons clemency on September 10, 1999.","state":"Illinois","race":"Hispanic","gender":"Male","ideologies":["Puerto Rican Independence","Anti-imperialist"],"affiliation":["FALN"],"era":"1980s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","charges":"Seditious conspiracy — FALN, in support of Puerto Rican independence","arrest_date":"1983-06-29","incarceration_date":"1983-06-29","release_date":"1999-09-10","sentence":"Long federal prison term; commuted by President Clinton September 1999 after 16 years","convicted":"Yes — federal seditious conspiracy, 1985"}]}' || true

php artisan prisoner:add '{"name":"Alberto Rodriguez","first_name":"Alberto","last_name":"Rodriguez","description":"Alberto Rodriguez was arrested on June 29, 1983 in Chicago, in the second wave of FALN arrests, after FBI surveillance documented him allegedly receiving bomb-making instruction from co-defendant Edwin Cortés. He was convicted of seditious conspiracy in support of Puerto Rican independence. He served 16 years before being released by President Clintons clemency on September 10, 1999.","state":"Illinois","race":"Hispanic","gender":"Male","ideologies":["Puerto Rican Independence","Anti-imperialist"],"affiliation":["FALN"],"era":"1980s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","charges":"Seditious conspiracy — FALN, in support of Puerto Rican independence","arrest_date":"1983-06-29","incarceration_date":"1983-06-29","release_date":"1999-09-10","sentence":"Long federal prison term; commuted by President Clinton September 1999 after 16 years","convicted":"Yes — federal seditious conspiracy, 1985"}]}' || true

