# === Operation Backfire / The Family — Eugene ELF cell ===

php artisan prisoner:add '{"name":"Daniel McGowan","first_name":"Daniel","middle_name":"Gerard","last_name":"McGowan","description":"Daniel Gerard McGowan is a former environmental and social-justice activist who participated in two Earth Liberation Front arsons in Oregon in 2001 — the burning of Superior Lumber and the burning of Jefferson Poplar Farm — both targeted for their roles in old-growth timber harvest and genetically modified poplar research, respectively.\n\nHe was arrested in December 2005 in the FBIs Operation Backfire roundup of the Eugene-based ELF cell known as The Family. He pleaded guilty to two counts of arson and conspiracy in a non-cooperating plea agreement. On June 4, 2007 he was sentenced by federal Judge Ann Aiken to 84 months (7 years) in federal prison, with the federal terrorism enhancement applied. He served his sentence largely at the federal Communications Management Unit at Marion, Illinois, the most restrictive non-supermax facility in the federal system, and was released to a halfway house in 2012 and home in 2013. The 2011 documentary If a Tree Falls: A Story of the Earth Liberation Front, in which he is the central figure, was nominated for an Academy Award. He has since worked as an organizer with the Center for Constitutional Rights.","state":"Oregon","race":"White","gender":"Male","birthdate":"1974-04-11","ideologies":["Environmental","Anti-capitalist"],"affiliation":["Earth Liberation Front"],"era":"2000s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (Communications Management Unit, Marion)","institution_state":"Illinois","charges":"Federal arson and conspiracy — two Earth Liberation Front arsons in Oregon, 2001 (Superior Lumber and Jefferson Poplar Farm)","arrest_date":"2005-12-07","incarceration_date":"2007-06-04","sentenced_date":"2007-06-04","release_date":"2013-06-05","sentence":"84 months (7 years) federal prison with terrorism enhancement","convicted":"Yes — non-cooperating guilty plea, U.S. District Court for the District of Oregon, June 2007"}]}' || true

php artisan prisoner:add '{"name":"Chelsea Gerlach","first_name":"Chelsea","middle_name":"Dawn","last_name":"Gerlach","description":"Chelsea Dawn Gerlach was a member of the Eugene-based Earth Liberation Front cell known as The Family. She was charged in the FBIs December 2005 Operation Backfire roundup with arsons including the 1996 Oakridge Ranger Station fire, the 1998 burning of the Vail ski resort in Colorado (the largest ELF action ever, $12 million in damage), and the 2000 toppling of an Oregon BPA electrical transmission tower. She pleaded guilty in December 2006. On June 4, 2007 she was sentenced by federal Judge Ann Aiken to 108 months (9 years) in federal prison with the federal terrorism enhancement applied.","state":"Oregon","race":"White","gender":"Female","ideologies":["Environmental"],"affiliation":["Earth Liberation Front"],"era":"2000s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","institution_state":"Oregon","charges":"Federal arson and conspiracy — Earth Liberation Front arsons including 1998 Vail ski resort, 1996 Oakridge Ranger Station, and 2000 BPA transmission tower","arrest_date":"2005-12-07","incarceration_date":"2007-06-04","sentenced_date":"2007-06-04","sentence":"108 months (9 years) federal prison with terrorism enhancement","convicted":"Yes — guilty plea, U.S. District Court for the District of Oregon, December 2006"}]}' || true

