php artisan prisoner:add '{"name":"Kevin Tubbs","first_name":"Kevin","last_name":"Tubbs","description":"Kevin Tubbs was a member of the Eugene-based Earth Liberation Front cell known as The Family. He was charged in the FBIs December 2005 Operation Backfire roundup and pleaded guilty. On June 4, 2007 he was sentenced by federal Judge Ann Aiken to 151 months (approximately 12.6 years) in federal prison with the federal terrorism enhancement applied — among the longest of the Operation Backfire sentences.","state":"Oregon","race":"White","gender":"Male","ideologies":["Environmental"],"affiliation":["Earth Liberation Front"],"era":"2000s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","institution_state":"Oregon","charges":"Federal arson and conspiracy — Earth Liberation Front participation in The Family Eugene cell","arrest_date":"2005-12-07","incarceration_date":"2007-06-04","sentenced_date":"2007-06-04","sentence":"151 months (approximately 12.6 years) federal prison with terrorism enhancement","convicted":"Yes — guilty plea, U.S. District Court for the District of Oregon, 2006-2007"}]}' || true

php artisan prisoner:add '{"name":"Suzanne Savoie","first_name":"Suzanne","last_name":"Savoie","description":"Suzanne Savoie was a member of the Eugene-based Earth Liberation Front cell known as The Family. She was charged in the FBIs December 2005 Operation Backfire roundup and pleaded guilty (with cooperation). On June 4, 2007 she was sentenced by federal Judge Ann Aiken to 51 months (4 years 3 months) in federal prison.","state":"Oregon","race":"White","gender":"Female","ideologies":["Environmental"],"affiliation":["Earth Liberation Front"],"era":"2000s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","institution_state":"Oregon","charges":"Federal arson and conspiracy — Earth Liberation Front participation in The Family Eugene cell","arrest_date":"2005-12-07","incarceration_date":"2007-06-04","sentenced_date":"2007-06-04","sentence":"51 months (4 years 3 months) federal prison","convicted":"Yes — guilty plea, U.S. District Court for the District of Oregon, 2006-2007"}]}' || true

php artisan prisoner:add '{"name":"Briana Waters","first_name":"Briana","last_name":"Waters","description":"Briana Waters was charged with serving as a lookout during the May 21, 2001 Earth Liberation Front arson at the University of Washingtons Center for Urban Horticulture in Seattle, the largest single ELF action in the United States. She maintained her innocence and went to trial in March 2008 — the only Operation Backfire defendant to do so. The first trial ended in conviction on two counts of arson and a 6-year federal sentence, but the conviction was overturned on appeal in 2009 because of suppressed evidence about a government witness. She was retried, pleaded guilty in 2012, and was resentenced. She is also a violinist and music teacher; her young daughter visited her in federal prison throughout her incarceration.","state":"Washington","race":"White","gender":"Female","ideologies":["Environmental"],"affiliation":["Earth Liberation Front"],"era":"2000s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","institution_state":"Washington","charges":"Federal arson — May 21, 2001 ELF arson at University of Washington Center for Urban Horticulture","arrest_date":"2006-03-15","incarceration_date":"2008-03-06","release_date":"2014-03-31","sentence":"6 years federal prison (2008 conviction); reversed on appeal 2009; resentenced after 2012 plea","convicted":"Yes — federal jury verdict 2008 (reversed); 2012 guilty plea on retrial"}]}' || true

php artisan prisoner:add '{"name":"Rebecca Rubin","first_name":"Rebecca","middle_name":"Jeanette","last_name":"Rubin","description":"Rebecca Jeanette Rubin was a Canadian-American member of the Eugene-based Earth Liberation Front cell known as The Family. She fled to Canada at the time of the December 2005 FBI roundup and remained a fugitive for seven and a half years. She voluntarily surrendered to U.S. authorities in November 2012 and pleaded guilty in 2013 to conspiracy and arson in connection with the 1998 Vail ski resort fire and other ELF actions. On January 27, 2014 she was sentenced to 60 months (5 years) in federal prison.","state":"Oregon","race":"White","gender":"Female","ideologies":["Environmental"],"affiliation":["Earth Liberation Front"],"era":"2000s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","institution_state":"Oregon","charges":"Federal conspiracy and arson — Earth Liberation Front participation including 1998 Vail ski resort fire","arrest_date":"2012-11-29","incarceration_date":"2014-01-27","sentenced_date":"2014-01-27","sentence":"60 months (5 years) federal prison","convicted":"Yes — guilty plea, U.S. District Court for the District of Oregon, 2013"}]}' || true

php artisan prisoner:add '{"name":"Joseph Dibee","first_name":"Joseph","middle_name":"Mahmoud","last_name":"Dibee","description":"Joseph Mahmoud Dibee was a member of the Eugene-based Earth Liberation Front cell known as The Family. Charged in the FBIs December 2005 Operation Backfire indictment, he fled the United States and lived as a fugitive for nearly thirteen years, traveling between Russia, Cuba, Mexico, and Central America. He was apprehended in August 2018 by Cuban authorities and turned over to U.S. agents. He pleaded guilty in 2022 to conspiracy and arson and was sentenced in 2022 to time served plus probation, accepting responsibility for the 1997 burning of the Cavel West horse-slaughtering plant in Redmond, Oregon.","state":"Oregon","race":"Arab","gender":"Male","ideologies":["Environmental","Animal rights"],"affiliation":["Earth Liberation Front","Animal Liberation Front"],"era":"2000s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","institution_state":"Oregon","charges":"Federal conspiracy and arson — Earth Liberation Front, including 1997 Cavel West horse-slaughtering plant arson; fled abroad as a fugitive 2006-2018","arrest_date":"2018-08-09","incarceration_date":"2018-08-09","sentenced_date":"2022-12-01","sentence":"Time served plus probation","convicted":"Yes — guilty plea, U.S. District Court for the District of Oregon, 2022"}]}' || true

php artisan prisoner:add '{"name":"Stanislas Meyerhoff","first_name":"Stanislas","middle_name":"Gregory","last_name":"Meyerhoff","description":"Stanislas Gregory Meyerhoff was a member of the Eugene-based Earth Liberation Front cell known as The Family. He was charged in the FBIs December 2005 Operation Backfire roundup. He pleaded guilty in December 2006 in a cooperating plea, providing testimony against other defendants. He was sentenced on June 4, 2007 by federal Judge Ann Aiken to 156 months (13 years) in federal prison with the federal terrorism enhancement applied. (Despite his cooperation, his guilty plea was to substantive arson counts and his sentence was the longest of the Operation Backfire defendants other than Tubbs.)","state":"Oregon","race":"White","gender":"Male","ideologies":["Environmental"],"affiliation":["Earth Liberation Front"],"era":"2000s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","institution_state":"Oregon","charges":"Federal arson and conspiracy — Earth Liberation Front participation in The Family Eugene cell, $20M of arsons 1996-2001","arrest_date":"2005-12-07","incarceration_date":"2007-06-04","sentenced_date":"2007-06-04","sentence":"156 months (13 years) federal prison with terrorism enhancement","convicted":"Yes — cooperating guilty plea, U.S. District Court for the District of Oregon, December 2006"}]}' || true

php artisan prisoner:add '{"name":"William Rodgers","first_name":"William","middle_name":"Cottrell","last_name":"Rodgers","aka":"Avalon","description":"William \"Avalon\" Cottrell Rodgers was a Prescott, Arizona bookstore owner and one of the central figures of the Eugene-based Earth Liberation Front cell known as The Family. He was arrested in December 2005 in the FBIs Operation Backfire roundup. He took his own life in the Coconino County Detention Facility in Flagstaff, Arizona on December 21, 2005 while awaiting trial — the first death of any Operation Backfire defendant. His suicide note read in part: I have chosen to leave to my own.","state":"Arizona","race":"White","gender":"Male","death_date":"2005-12-21","ideologies":["Environmental","Anti-capitalist"],"affiliation":["Earth Liberation Front"],"era":"2000s","in_custody":false,"released":false,"cases":[{"institution_name":"Coconino County Detention Facility","institution_city":"Flagstaff","institution_state":"Arizona","charges":"Federal conspiracy and arson — Earth Liberation Front participation in The Family Eugene cell, $20M of arsons 1996-2001","arrest_date":"2005-12-07","incarceration_date":"2005-12-07","death_in_custody_date":"2005-12-21","sentence":"Awaiting trial; took his own life in pretrial detention December 21, 2005","convicted":"No — died awaiting trial"}]}' || true

