php artisan prisoner:add '{"name":"Kevin Kjonaas","first_name":"Kevin","last_name":"Kjonaas","description":"Kevin Kjonaas was the President of Stop Huntingdon Animal Cruelty USA (SHAC USA), the U.S. arm of the international campaign to shut down the contract animal-research lab Huntingdon Life Sciences. He was indicted in May 2004 along with five other SHAC USA activists and the SHAC USA organization itself, in the first federal prosecution under the Animal Enterprise Terrorism Act. The defendants were charged with using the SHAC USA website and protests to incite stalking and harassment of HLS personnel and clients — none of the defendants were charged with personally engaging in any threatening communication or vandalism.\n\nA federal jury in Trenton, New Jersey convicted the SHAC 7 in March 2006. Kjonaas received the longest sentence of the human defendants — 6 years in federal prison.","state":"New Jersey","race":"White","gender":"Male","ideologies":["Animal rights","First Amendment"],"affiliation":["Stop Huntingdon Animal Cruelty USA"],"era":"2000s","in_custody":false,"released":true,"cases":[{"institution_name":"Federal Bureau of Prisons (location varied)","institution_state":"New Jersey","charges":"Federal Animal Enterprise Protection Act and interstate stalking — first federal prosecution under the Animal Enterprise Terrorism Act","arrest_date":"2004-05-26","incarceration_date":"2006-09-12","sentenced_date":"2006-09-12","sentence":"6 years federal prison","convicted":"Yes — federal jury verdict, U.S. District Court for the District of New Jersey, March 2006"}]}' || true

